insert into course (code, title, period, department, coordinator, coordinator_email, prerequisites, description, details, sort) values
  ('BIO2004', 'General Zoology', 'P1', 'MSP', 'Dr. John Sloggett', 'j.sloggett@maastrichtuniversity.nl', NULL, 'Animals are everywhere, on land, in water and in the air. They comprise an extremely diverse kingdom, with all species being a mixture of shared and unique biological characteristics. These characteristics are a product of evolutionary history and adaptation to the abiotic and biotic environment. In this course you will focus on the major groups within the animal kingdom, what defines them, how they are organised and how they are related to each other; you will also examine the specific adaptations of certain animals in more depth. The question “What is an animal?” will be considered as will the issue of how animals are grouped and related to each other. This will be done in the context of the major phyla, their defining morphological, anatomical and physiological features and the sorts of adaptations and behaviours that they exhibit. You will also examine certain adaptations such as bright colouration, feeding or parental care in greater depth, using particular animal groups as a source of examples.', '{"level": "2000-level", "objectives": ["To characterise the defining biological features of the animal kingdom.", "To provide an overview of the characteristics of the major animal groups.", "To explain the systematics and phylogenetics of major groups within the animal kingdom.", "To place the morphological, anatomical and behavioural aspects of animal groups in an evolutionary context.", "To examine in more detail particular biological adaptations using specific animal groups as examples."], "literature": "Miller, S.A & Tupper, T.A. (2023) Zoology, 12th edition, ISBN: 978-1266701634.", "instructional_format": "One lecture, one PBL tutorial, one interactive lecture/tutorial.", "assessment": ["Tutorial grade", "Poster", "Exam"], "genai": "Not permitted"}'::jsonb, 0),
  ('CHE1101', 'Introduction to Chemistry', 'P1', 'MSP', 'Dr. Chris Bahn', 'chris.bahn@maastrichtuniversity.nl', NULL, 'The emphasis of this course will be on a number of essential topics in modern chemistry. The first part of the course will provide an overview of the structure of atoms and their place in the periodic table as well as the properties of various types of chemical bonds and chemical bonding theory. The second part will present an introduction to physical chemistry with important topics such as the characteristics of gases/liquids/solids, thermodynamics and reaction kinetics. In the final part, the course focuses on a selection of important chemical subjects which form the basis of chemical studies in general. Typical topics in this part of the course are based on acid-base chemistry and electrochemistry.', '{"level": "1000-level", "corequisites": "PRA1101 Introduction to Scientific Research I (only in Period 1)", "objectives": ["To gain an understanding of the nature of atoms and their organization in the periodic table;", "To recognize various classes of chemical compounds and to understand their chemical and physical properties;", "To obtain an understanding of the physical chemistry fundamentally important to biological and chemical processes, with an emphasis on thermodynamics and kinetics;", "To use concepts acquired from kinetics, thermodynamics, acid-base chemistry, and electrochemistry, to predict the potential outcome of chemical reactions;", "To acquire sufficient background for more advanced courses in chemistry, biochemistry and the life sciences."], "literature": "Chemistry, via OpenStax (https://openstax.org/details/books/chemistry-atoms-first-2e) ISBN-10: 1-947172-63-8 ISBN-13: 978-1-947172-63-0", "instructional_format": "Lectures, Q&A sessions, and tutorial group meetings.", "assessment": ["A midterm examination consisting of multiple choice, short answer, calculation and explanation questions;", "Weekly homework assignments", "A final examination consisting of multiple choice, short answer, calculation and explanation questions."], "genai": "Not permitted"}'::jsonb, 1),
  ('CHE2004', 'Spectroscopy', 'P1', 'MSP', 'Annelies van der Bok', 'anneliesvanderbok@maastrichtuniversity.nl', 'CHE2009 Fundamentals of Organic Chemistry (or CHE2001 Organic Chemistry)', 'The course will focus on several spectroscopic and chromatographic techniques, such as Nuclear Magnetic Resonance (NMR), UV-Vis spectroscopy, FT-IR spectroscopy, gas and liquid chromatography, and mass spectrometry. First, the theoretical background and physical basics of these techniques will be discussed. Then, the reading and interpretation of spectral analysis will be covered. The main focus of the course will be on acquiring knowledge and practical expertise to characterize chemical compounds, primarily organic molecules. You will learn to develop an analytical strategy to get structural information for unknown molecules by combining the experimental data of the abovementioned techniques.', '{"level": "2000-level", "objectives": ["To have a basic understanding of the theoretical background of the measurement principles typically used in spectroscopy and spectrometry.", "To learn to read and interpret the diverse types of spectral data obtained from NMR, MS, UV-Vis and FT-IR.", "To learn to correlate molecular structure with a variety of spectral features in NMR, MS, UV-Vis and FT-IR spectra.", "To develop an analytical strategy to identify an unknown compound and report it concisely."], "literature": "Spectroscopy; Lampman, Pavia, Kriz, Vyvyan; 4th or 5th edition (International Edition): Brooks/Cole.", "instructional_format": "Lectures and tutorial group meetings.", "assessment": ["Weekly graded exercises", "A ‘midterm’ assignment combining spectral analysis of NMR, FT-IR, MS, and UV-Vis", "A final examination on the spectral analysis and theoretical background of these techniques. The exam consists of open questions and problems."], "genai": "Not permitted"}'::jsonb, 2),
  ('CHE3010', 'Inorganic Chemistry', 'P1', 'MSP', 'Dr. Giuditta Perversi', 'g.perversi@maastrichtuniversity.nl', 'CHE2010 General Chemistry', 'This course will immerse the students into the world of chemistry beyond carbon, and aims to provide a broad survey of the chemistry available when transition metals are involved. We will build upon the generalized bonding knowledge from General Chemistry to expand the Molecular Orbital Theory all the way to the complex geometries of the d-block. The Crystal Field Theory (CFT) of d-block complexes will correlate with their point group symmetry, and then expanded to the more comprehensive Ligand Field Theory (LFT). In the second half of the course, the newfound knowledge will be used to understand the properties of transition metal complexes: IR and Raman activities will be derived with symmetry analysis; colours and UV-Vis transitions will be explained. We will close our course with fundamental aspects of organometallic reactivity and catalysis are provided.', '{"level": "3000-level", "corequisites": "PRA3028 Inorganic Synthesis", "recommended": "The course integrates nicely with Spectroscopy (CHE2004) NOTE: Waivers can be granted (knowing that there is material you will not be familiar with) if you have passed CHE2009 Fundamentals of Organic Chemistry.", "objectives": ["Acquire a comprehensive understanding of bonding throughout the periodic table (including d and f block), and its correlation with periodic trends", "Systematise molecular geometry approaches through VESPR (and its pitfalls) and recognize associated point-group symmetries", "Lay the foundations of more complex bonding in d-block complexes (Crystal field theory, full Molecular Orbital of octahedral d-block complexes)", "Provide a rigorous theoretical basis of the experimental analysis of transition metal compounds (informed by the bonding), especially in terms of symmetry-analysis of Raman/IR activity", "Understand the appearance of colour in inorganic compounds and their UV-Vis transitions", "Introduce organometallic reactivity, and basic understanding of catalytic cycles"], "literature": "• Shriver and Atkins: Inorganic Chemistry (Oxford); • Huheey, Keiter, Keiter: Inorganic Chemistry (Harper Collins); • Wulfsberg: Inorganic Chemistry (University Science Books).", "instructional_format": "Flipped classroom: the students are provided with content ahead of the week. The content is required to tackle the tutorial problems and homework. A weekly plenary Q/A wraps up after the tutorials.", "assessment": ["Midterm exam (week 3 or 4);", "Final exam (Week 7);", "Weekly homework and Tutorial group participation (Week 1 to Week 6);"], "genai": "Not permitted"}'::jsonb, 3),
  ('INT2013', 'Fundamentals of Science Education', 'P1', 'MSP', 'Dr. May Lee', 'may.lee@maastrichtuniversity.nl', 'PRO1002: Project Period (1000-level)', 'Science teaching is a complex craft that draws on knowledge and skills from multiple fields. Learning to use high-leverage teaching practices well takes time because it requires principled reasoning—deciding which practice, in what form, best fits your students, the science content, and the classroom context. In this module, we use cognitive and social constructivist perspectives to examine how students learn in relation to these high-leverage practices. You will become familiar with key features of effective science teaching and learn to identify them through observations of high school science classrooms. The module culminates in designing and teaching a science lesson to your peers and writing a report that uses course readings and activities to describe, analyse, and reflect on your peer-taught lesson.', '{"level": "2000-level", "objectives": ["At the end of this course, students will be able to:", "recognize instances of high-leverage teaching practices in observations of high school teachers’ science classrooms", "define learning objectives that address a disciplinary core idea, a scientific and engineering practice, and a crosscutting concept", "identify an anchoring event that explains a big idea in science", "develop and implement a lesson plan that addresses the defined learning objectives", "assess students’ sensemaking of ideas from implemented lesson plan", "self-assess and reflect on their development and implementation of lesson plan with respect to the high-leverage teaching practices, Next Generation Science Standards, and Ambitious Science Teaching"], "literature": "We will use primary literature, which are accessible through the course Canvas page. No textbook is required.", "instructional_format": "Lectures will be interactive and address different aspects of teaching secondary science. During tutorials, students will discuss readings, practice different teacher talk moves, and work on the lessons they will eventually teach to others.", "assessment": ["The course grade is based on 60% individual work (vignette/reading comments, field observations, individual lesson report) and 40% group work (lesson plan, peer teaching with peer review, and group lesson report)."], "genai": "Not permitted"}'::jsonb, 4),
  ('MAT2007', 'Introduction to Programming', 'P1', 'MSP', 'Panos Christakoglou', 'panos.christakoglou@maastrichtuniversity.nl', NULL, 'The course serves as an introduction to programming tailored for students without prior experience. It is divided into two parts: the first part focuses on basic programming concepts, principles, and problem- solving techniques, emphasising language-agnostic approaches. The second part presents the basics of C++, and introduces elements of Python and R programming. The course concludes with an exploration of Language Model Generation (LMG) using examples from ChatGPT.', '{"level": "2000-level", "objectives": ["Develop an understanding of basic programming concepts such as variables, control structures, functions, and data types.", "Learn to formulate and solve problems algorithmically, using appropriate programming constructs.", "Acquire skills in data manipulation and analysis through introductory exposure to the Python programming language.", "Get familiar with Object Oriented Programming principles with practical experience in e.g. C++.", "Explore how programming can be applied in various scientific domains, including data analysis, simulation, and modelling.", "Explore the integration of language model generation techniques, such as the ones used by ChatGPT, into programming workflows to enhance code generation, documentation, and natural language understanding tasks."], "literature": "• “Programming Logic and Design” by Joyce Farrell • “C++ Programming Language\" by Bjarne Stroustrups • “An Introduction to Python Programming for Scientists and Engineers” by Johnny Wei-Bing Lin et al. • \"Deep Learning\" by Ian Goodfellow, Yoshua Bengio, and Aaron Courville", "instructional_format": "Lectures, tutorials and lab group meetings.", "assessment": ["Attendance", "Programming assignments", "Lab exercises"], "genai": "Not permitted"}'::jsonb, 5),
  ('PHY1101', 'Introduction to Physics', 'P1', 'MSP', 'Dr. Lorenzo Reverberi', 'l.reverberi@maastrichtuniversity.nl', NULL, 'Physics is the natural science that aims to understand the constituents of the universe and their interactions and behaviour, from subatomic particles to the largest cosmic structures. This course will introduce participants to what studying physics at university and thinking like a physicist is all about. We will start at the very basics – units, measurements, motion – and gradually build towards the revolutions of the 20th century: relativity and quantum physics. Topics will be covered at an introductory but rigorous level, and we will put special emphasis on the history of the scientific discoveries, as well as practical applications of physics through estimation, model-building, and real-life examples of the concepts.', '{"level": "1000-level", "objectives": ["Outline key historical developments of the field of physics and its major branches today", "Describe basic physical phenomena using appropriate terminology and notation", "Check dimensional consistency of relations, and convert between units", "Apply dimensional and unit analysis to identify patterns and relationships between quantities, and explain natural phenomena", "Perform reasonable order-of-magnitude estimates for various physical quantities", "Identify suitable idealisations and models of natural phenomena, and be aware of their approximations and limitations", "Use physical laws and principles to interpret and solve problems, for example: Newton’s Laws; conservation of energy, linear momentum and angular momentum; laws of thermodynamics; relativistic velocity addition, Lorentz contraction and time dilation."], "literature": "[1] University Physics volumes 1, 2 & 3, OpenStax College, https://openstax.org/. [2] T. A. Moore, Six Ideas that Shaped Physics (1998), WCB/McGraw-Hill [3] L. Bloomfield, How Things Work: The Physics of Everyday Life (2015), John Wiley & Sons. [4] W. T. Griffith and J. W. Brosing, Physics of Everyday Phenomena (2009), McGraw-Hill. Additional material and resources will be provided during the course.", "instructional_format": "One lecture and two tutorials per week.", "assessment": ["Weekly quizzes", "Weekly tutorial tasks", "Final exam"], "genai": "Not permitted"}'::jsonb, 6),
  ('PHY2009', 'Stellar Astronomy', 'P1', 'MSP', 'Mr. Chad Ellington', 'chad.ellington@maastrichtuniversity.nl', NULL, 'This course begins with an overview of information available by studying the spectrum of light from objects within our universe. We then look at our own star, the Sun, covering what humanity has learned thus far about its interior structure/composition. Next, we study properties of other stars including: how they form, their ‘lifetimes’, ‘evolution’ & the many remnants they leave behind.', '{"level": "2000-level", "objectives": ["Review the electromagnetic spectrum and usefulness of spectroscopic observations, including: blackbody thermal radiation, emission/absorption spectra and how they can determine chemical composition, relative radial velocities, surface temperatures and luminosities of objects throughout our universe;", "Identify the overall structure of our Sun from core to corona, covering: nuclear fusion, highlighting structures/processes of energy transfer & how each region can be studied;", "Describe the conditions under which stars form & why their formation mass is so important;", "Synthesize apparent magnitude, surface temperature & parallax to determine information such as: stellar luminosity (absolute magnitude), distance & stellar size…comparing/contrasting with our own Sun & applying to more distant stars for which parallax information is lacking;", "Recognize spectral types of stars, being able to identify them based on surface temperature (color), spectral features, stellar mass and/or luminosity class;", "Differentiate types of binary stars and utilize observational data to find their physical properties, such as combined mass, individual mass, physical size and orbital separation (as applicable);", "Illustrate color-magnitude (H-R) diagrams, locating major types of stars as well as explaining differences for young versus old star clusters…identifying the turn-off point and how/why it is utilized to determine star cluster ages;", "Understand the importance of intrinsic variable stars, especially pulsating and cataclysmic variables and their contributions towards the cosmological distance ladder, being able to identify types based upon light curve and spectroscopic observations;", "Apply the cosmological distance ladder to determine distances to particular types of stars;", "Discuss stellar changes from formation to death, highlighting differences of low versus high mass stars from that of our Sun and how their remnants contribute to future star formation and planet formation."], "literature": "• Ryden, B. & Peterson, B. (2020). Foundations of Astrophysics (1st ed.). Cambridge; • Astronomy, OpenStax College. Retrieved via: https://openstax.org/details/books/astronomy.", "instructional_format": "Each week of this course focuses on various topics concerning stars and stellar evolution, consisting of overview lectures and discussion tutorial group meetings. The first meeting may introduce the weekly group assignments/exercises with discussion questions where results with further discussions occurs in the subsequent tutor group meetings. There may be mathematical individual exercises, which may include independent research and/or observations.", "assessment": ["Conceptual assessments and diagnostics/surveys;", "Tutorial exercises/problems and tutorial proposal;", "Midterm;", "Final examination."], "genai": "Not permitted"}'::jsonb, 7),
  ('BIO1101', 'Introduction to Biology', 'P2', 'MSP', 'David Cortens', 'david.cortens@maastrichtuniversity.nl', NULL, 'This course provides an overview of the major branches of biological sciences and the fundamental processes relevant to each. The major topic areas covered are ecology, evolution, cell and molecular biology, genetics, and organismal biology. For each topic, you will explore how the content connects to the central concepts of all biological sciences: regulation, self- organization, evolution, inheritance, communication, and interaction.', '{"level": "1000-level", "corequisites": "PRA1102 Introduction to Scientific Research II", "objectives": ["After this course, students should be able to:", "Apply basic knowledge of ecology, evolution, and molecular and organismal biology to discuss cutting-edge biological research and its impacts on society;", "Explain how the following six core biological concepts apply to the multiple scales of organization and time in biological systems: regulation, self-organization, evolution, inheritance, communication, and interaction;", "Do calculations relevant for Mendelian inheritance."], "literature": "Taylor et al. (2021). Campbell Biology: Concepts & Connections (10th edition, global edition). Pearson. ISBN10: 1-292-40134-6 ISBN13: 978-1-292-40134-8", "instructional_format": "One question and answer session and two PBL tutorials per week.", "assessment": ["Evaluation of student performance will be based on:", "Contribution to the discussion during tutorial meeting;", "A presentation in week 4 of the course;", "A final written exam at the end of the course."], "genai": "Not permitted"}'::jsonb, 8),
  ('INT1101', 'Introduction to Liberal Arts & Sciences', 'P2', 'MSP', 'Dr. Hanne Diliën', 'hanne.dilien@maastrichtuniversity.nl', NULL, 'The first part of the course aims at providing you with an understanding of the natural sciences from a philosophical perspective. What is science? What is the scientific methodology? What are the norms and values in a scientific environment? The variety of perspectives that you are introduced to when answering these questions will allow you to develop critical thinking skills and provide you with insight that can be used in your personal development as a scientist. After exploring the philosophy of science in the first part of the course, the second part teaches you to apply and communicate your knowledge and ideas effectively by devoting attention to argumentation and science communication.', '{"level": "1000-level", "corequisites": "PRA1102 Introduction to Scientific Research II", "objectives": ["The objective of this course is to make you think about the natural sciences from a philosophical perspective: what is science; what is the scientific method? The course also challenges you to develop your intellectual and generic skills further: how to integrate different perspectives; what is ethical in science; how to communicate in/about science? To achieve these, you will be able:", "To understand the main theoretical approaches within the philosophy of science and its usefulness in a natural sciences context;", "To understand the nature of academic knowledge and the process of scientific development;", "To know how science is done (“the scientific method”);", "To discuss the importance norms and values in scientific environments;", "To explore the structure and use of basic argumentation in various formats of communication;", "To use historical and sociological case studies of scientific practice in mastering the above objectives."], "literature": "All students are required to read: • Peter Godfrey-Smith: Theory and Reality: An Introduction to the Philosophy of Science, Second Edition. (ISBN: 978-0-2266-1865-4) In addition, students will study a variety of articles and book chapters, which will be made available online on a weekly basis.", "instructional_format": "This course is structured around PBL assignments with weekly lectures to provide background to the topics discussed.", "assessment": ["Assessments in this course include:", "An essay assignment;", "A debate assignment."], "genai": "Not permitted"}'::jsonb, 9),
  ('MAT2009', 'Multivariable Calculus', 'P2', 'MSP', 'Dr. Mariet Hofstee', 'mariet.hofstee@maastrichtuniversity.nl', 'MAT2006 Calculus', 'Multivariate calculus is the extension of calculus of one variable to calculus with functions of several variables: notably the differentiation and integration of functions involving multiple variables. Considerable attention will be devoted to vector calculus, with focus on differentiation and integration of vector fields, primarily in 3-dimensional Euclidean space.', '{"level": "2000-level", "note": "this course fulfils the MAT requirement", "recommended": "MAT2004 Linear Algebra (highly recommended)", "objectives": ["This course is intended to introduce Science students in the essential mathematics to describe continuous systems with multiple variables."], "literature": "Open Educational Resources (OER) available online are used. Based on these books a list of learning goals, keywords and references is posted each week, allowing students to use any books they have available in addition to the online resources. Main resources listed here, additional links provided on Canvas: • Active Calculus - Multivariable (Main resource), https://activecalculus.org/multi/root-1-2.html • Openstax Calculus 3, https://openstax.org/details/books/calculus-volume-3/ Some additional resources: • https://math.libretexts.org/Bookshelves/Calculus/Map%3A_Calculus__Early_Transcendentals_(St ewart) , A general Calculus Textmap organized around the textbook “Calculus: Early Transcendentals” by James Stewart • https://www.mecmath.net/ , Vector Calculus by Michael Corral, includes numerical examples (Java based)", "instructional_format": "Lecture and tutorials. The first tutorial practices basic techniques, the second tutorial class each week uses a mixture of some more involved exercises, case studies and computer modeling.", "assessment": ["The assessment for the course will consist of:", "Online quizzes on WeBWorK;", "Written midterm exam;", "Written final exam;", "Short written final paper demonstrating the use of multivariable Calculus in your field of interest"], "genai": "Not permitted"}'::jsonb, 10),
  ('PHY2010', 'Galactic Astronomy', 'P2', 'MSP', 'Mr. Chad Ellington', 'chad.ellington@maastrichtuniversity.nl', NULL, 'This course begins with an exploration of our Milky Way Galaxy, identifying its overall structure and our Sun’s place within which. Continuing outward, we study properties of other galaxies, highlighting properties of varying types, how they form and change with time. Finishing up with how large scale observations lead us to the initial conditions of our universe and the Hot Big Bang theory itself.', '{"level": "2000-level", "recommended": "PHY2009 Stellar Astronomy", "objectives": ["Illustrate the size/structure of our Milky Way Galaxy, how we are able to measure motions of stars/gas clouds, map its overall structure and determine our place within which;", "Compare/contrast the shapes, sizes & compositions of: spiral, elliptical, peculiar & irregular galaxies; being able to classify to which type they belong based upon imagery, orbital motions of bodies within which and/or physical content descriptions;", "Evaluate the likelihood of various astrophysical objects being found within the spiral, elliptical, peculiar & irregular galaxy types;", "Evaluate observational evidence to differentiate between the top-down and bottom-up models describing galactic formation;", "Critique the competing models explaining the presence of galactic spiral arms and central bars;", "Explain the methods of determining distances to galaxies within the cosmological distance ladder, applying them to various galactic structures;", "Compute the distances at which galactic systems tidally disrupt each other.", "Breakdown the historical classifications of active galaxies into the subcategories of: radio galaxies, Seyfert galaxies, quasars or blazars; understanding their impact on galactic evolution and why they are observed almost exclusively at cosmological distances;", "Describe the various pieces of evidence for dark matter within most galaxies and clusters of galaxies, computing galactic masses when possible;", "Relate how observations of distant supernovae led to the discovery that our universe is accelerating in its expansion rate;", "Identify the key predictions/observations for the origin of our universe."], "literature": "• Ryden, B. & Peterson, B. (2020). Foundations of Astrophysics (1st ed.). Cambridge; • Astronomy, OpenStax College. Retrieved via: https://openstax.org/details/books/astronomy.", "instructional_format": "Each week of this course focuses on various topics concerning our Milky Way, other galactic types, large-scale structure of our universe and conditions in the early universe, consisting of overview lectures and discussion group meetings. The first meeting may introduce the weekly group assignments/exercises with discussion questions where results with further discussions occurs in the subsequent tutor group meetings. There may be mathematical individual exercises, which may include independent research and/or observations.", "assessment": ["Conceptual assessments and diagnostics/surveys;", "Tutorial exercises/problems;", "Tutorial proposal", "Midterm;", "Final examination."], "genai": "Not permitted"}'::jsonb, 11);
